import { afterEach, beforeEach, describe, expect, it } from "vitest";
import { getAgentSessionId } from "./getAgentSessionId.js";
const ENV_VARS = ["CLAUDE_CODE_SESSION_ID", "CODEX_THREAD_ID"];
describe("getAgentSessionId", () => {
    let saved = {};
    beforeEach(() => {
        saved = {};
        for (const key of ENV_VARS) {
            saved[key] = process.env[key];
            delete process.env[key];
        }
    });
    afterEach(() => {
        for (const key of ENV_VARS) {
            if (saved[key] === undefined) {
                delete process.env[key];
            }
            else {
                process.env[key] = saved[key];
            }
        }
    });
    it("returns the Claude Code session id", () => {
        process.env.CLAUDE_CODE_SESSION_ID = "claude-123";
        expect(getAgentSessionId()).toBe("claude-123");
    });
    it("returns the Codex thread id when Claude's is absent", () => {
        process.env.CODEX_THREAD_ID = "codex-abc";
        expect(getAgentSessionId()).toBe("codex-abc");
    });
    it("prefers the Claude session id when both are set", () => {
        process.env.CLAUDE_CODE_SESSION_ID = "claude-123";
        process.env.CODEX_THREAD_ID = "codex-abc";
        expect(getAgentSessionId()).toBe("claude-123");
    });
    it("returns null when no stable agent session id is exposed (e.g. Cursor)", () => {
        expect(getAgentSessionId()).toBeNull();
    });
});
